script.text:

function active$FormApprovalIndicator(f) {
  f.add_onResponseComplete(on$FormApprovalIndicator$ResponseComplete);
  setDefaultValue$FormApprovalIndicator(f);
}
function scatter$FormApprovalIndicator(f) {setDefaultValue$FormApprovalIndicator(f);}
function close$FormApprovalIndicator(f) {try {f.remove_onResponseComplete(on$FormApprovalIndicator$ResponseComplete)} catch (ex) {}}
function on$FormApprovalIndicator$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'u_status');
      break;
    default:
      break;
  }
}
function setDefaultValue$FormApprovalIndicator(f) {if (f._action == 'New') {f.setItemValue('loai_duyet',  f.grid._approvalType);}}

      &ScriptIrregular;
